DROP TABLE IF EXISTS empresas;
CREATE TABLE empresas (
      `_idempresas` int(11) NOT NULL AUTO_INCREMENT,
      `fecha` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
      `tipotcaso` varchar(155) DEFAULT NULL,   
      `sector` varchar(155) DEFAULT NULL,
      `empresa` varchar(155) DEFAULT NULL,
      `web` varchar(155) DEFAULT NULL,
      `telefono` varchar(55) DEFAULT NULL,
      `ciudad` varchar(155) DEFAULT NULL,
      `numempleados` varchar(55) DEFAULT NULL,
      `ceo_director` varchar(155) DEFAULT NULL,
      `nombre` varchar(155) DEFAULT NULL,
      `apellidos` varchar(155) DEFAULT NULL,
      `cargo` varchar(155) DEFAULT NULL,
      `cif` varchar(155) DEFAULT NULL,
      `email` varchar(155) DEFAULT NULL,
      PRIMARY KEY (`_idempresas`));

;      